// filepath: d:\VSCODE\real time project\CinemaOne\frontend\src\pages\HomePage.js
import React, { useState } from 'react';
import './HomePage.css';
import MovieList from '../components/MovieList';
import ExclusiveContent from '../components/ExclusiveContent';

// Enhanced Hero Banner with background image, overlay, and animation
const HeroBanner = () => (
  <section className="hero-banner" style={{
    minHeight: '60vh',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    background: 'linear-gradient(120deg, #1e293b 0%, #6366f1 100%)',
    color: '#fff',
    textAlign: 'center',
    padding: '4rem 1rem',
    borderRadius: '32px',
    marginBottom: '3rem',
    boxShadow: '0 8px 32px rgba(99,102,241,0.13)'
  }}>
    <h1 style={{ fontSize: '3rem', fontWeight: 800, marginBottom: '1rem' }}>
      Discover Movies Like Never Before
    </h1>
    <p style={{ fontSize: '1.25rem', maxWidth: 600, marginBottom: '2rem' }}>
      Explore exclusive content, trending movies, and your personalized watchlist—all in one place.
    </p>
    <button className="navbar-cta" style={{ fontSize: '1.2rem' }}>
      Browse Now
    </button>
  </section>
);

// Animated Search Bar with icon
const SearchBar = ({ onSearch }) => {
  const [query, setQuery] = useState('');
  const handleChange = (e) => {
    setQuery(e.target.value);
    onSearch(e.target.value);
  };
  return (
    <div className="search-bar">
      <span className="search-icon" role="img" aria-label="search">🔍</span>
      <input
        type="text"
        placeholder="Search movies or content..."
        value={query}
        onChange={handleChange}
        aria-label="Search movies or content"
      />
    </div>
  );
};

// Featured Movie Card
const FeaturedMovie = ({ movie }) => (
  <div className="featured-movie-card">
    <img src={movie.poster} alt={movie.title} />
    <div className="featured-movie-info">
      <h3>{movie.title}</h3>
      <div className="rating">
        <span role="img" aria-label="star">⭐</span> {movie.rating}
      </div>
      <button className="watch-btn">Watch Now</button>
    </div>
  </div>
);

// Animated, sticky navigation bar
const Navbar = () => (
  <nav className="navbar">
    <div className="navbar-brand">
      <span className="brand-highlight">CinemaOne</span>
    </div>
    <ul className="navbar-links">
      <li><a href="#now-showing">Now Showing</a></li>
      <li><a href="#exclusive">Exclusive</a></li>
      <li><a href="#about">About</a></li>
    </ul>
    <div className="navbar-profile">
      <img src="/images/user-avatar.png" alt="User" className="navbar-avatar" />
    </div>
  </nav>
);

// Animated section divider
const SectionDivider = ({ children }) => (
  <div className="section-divider">
    <span>{children}</span>
  </div>
);

// Animated scroll-to-top button
const ScrollToTopButton = () => {
  const [visible, setVisible] = useState(false);
  React.useEffect(() => {
    const onScroll = () => setVisible(window.scrollY > 300);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);
  return visible ? (
    <button
      className="scroll-to-top"
      onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
      aria-label="Scroll to top"
    >
      ⬆️
    </button>
  ) : null;
};

const HomePage = () => {
  const [search, setSearch] = useState('');

  const movies = [
    { id: 1, title: 'Movie 1', price: 10, poster: '/images/movie1.jpg', rating: 4.5 },
    { id: 2, title: 'Movie 2', price: 15, poster: '/images/movie2.jpg', rating: 4.2 },
    { id: 3, title: 'Movie 3', price: 12, poster: '/images/movie3.jpg', rating: 4.8 },
