    ))}
  </div>
</section>
        <SectionDivider>Exclusive</SectionDivider>
        <section className="section" id="exclusive">
          <div className="section-header">
            <h2>Exclusive Content</h2>
            <a href="#exclusive" className="see-all-link">See All</a>
          </div>
          <ExclusiveContent content={filteredContent} />
        </section>
      </div>
