  background: '#181c24',
  color: '#b2bec3',
  padding: '2rem 0',
  textAlign: 'center',
  borderRadius: '24px 24px 0 0',
  marginTop: '3rem'
}}>
  <div style={{ marginBottom: '1rem' }}>
    <a href="#" style={{ color: '#00b894', margin: '0 1rem' }}>About</a>
    <a href="#" style={{ color: '#00b894', margin: '0 1rem' }}>Help</a>
